# AI deployment liability risk assessment

from dataclasses import dataclass
from typing import Literal

@dataclass
class LiabilityRiskProfile:
    deployment_name: str
    harm_categories: list[str]  # e.g. ["financial","reputational","physical","discriminatory"]
    max_single_incident_gbp: float
    incidents_per_year_estimate: float
    affected_population_size: int
    involves_eu_subjects: bool
    eu_ai_act_high_risk: bool
    human_oversight_level: Literal["none","sampling","mandatory_pre_action","real_time"]
    vendor_indemnity_cap_gbp: float
    customer_liability_cap_gbp: float
    insurance_coverage_gbp: float

    def annual_expected_liability_gbp(self) -> float:
        return self.max_single_incident_gbp * self.incidents_per_year_estimate

    def uninsured_exposure_gbp(self) -> float:
        return max(0, self.annual_expected_liability_gbp() - self.insurance_coverage_gbp)

    def liability_risk_score(self) -> str:
        exposure = self.annual_expected_liability_gbp()
        uninsured = self.uninsured_exposure_gbp()
        if self.eu_ai_act_high_risk and self.human_oversight_level == "none":
            return "critical"
        if uninsured > 5_000_000 or exposure > 20_000_000:
            return "high"
        if uninsured > 500_000 or self.eu_ai_act_high_risk:
            return "medium"
        return "low"

    def summary(self) -> dict:
        return {
            "deployment": self.deployment_name,
            "annual_expected_liability": round(self.annual_expected_liability_gbp()),
            "uninsured_exposure": round(self.uninsured_exposure_gbp()),
            "eu_ai_act_high_risk": self.eu_ai_act_high_risk,
            "human_oversight": self.human_oversight_level,
            "risk_score": self.liability_risk_score(),
        }
